//! # SketchBackend — `WeightBackend` over a KNOT-format SK32 sketch file
//!
//! The committed `<model>-sketches.knot` artifacts (produced by
//! `generate-sketches.py` / `sketch_knot_format.py`) are NOT `.rknot`
//! files. They reuse the dense **"KNOT"** four-byte magic and carry a
//! completely different compression scheme:
//!
//!   - `.rknot` (magic `"RKNOT\x02"`): per-layer **standing-wave**
//!     QuantBlocks on a `k << d` standing-index subspace, decoded by
//!     `decoder::decode_ffn_block`.
//!   - sketches (`"KNOT"` magic): per-tensor **rank-K SVD sketches**
//!     ("SK32"), i.e. a low-rank factorization `W ≈ U · diag(σ) · Vᵀ`
//!     with U/σ/V q8-quantized. No standing subspace at all.
//!
//! Because the two formats share no body layout, `RknotBackend::open`
//! cannot read a sketch file — it fails with `BadMagic{found:[75,78,79,
//! 84,1,0]}` ("KNOT" + v1). Rather than mangle the standing-wave reader,
//! this module is a parallel `WeightBackend` that reconstructs each
//! requested tensor from its SK32 factors on demand. `RknotBackend::open`
//! sniffs the magic and dispatches here, so
//! `--rknot <sketches.knot> --dense <dense>` works end to end.
//!
//! ## On-disk layout (mirrors `sketch_knot_format.py:write_sketches_knot`)
//!
//! ```text
//! magic        : 4 bytes  "KNOT"
//! version      : 2 bytes  u16 LE (== 1)
//! meta_len     : 4 bytes  u32 LE
//! meta_json    : meta_len bytes  (UTF-8 JSON; see below)
//! pad          : (10 + meta_len) padded up to a 4-byte boundary
//! codec_marker : 1 byte   (CODEC_MARKER_FP32)
//! payload      : rest     concat of per-sketch (u_q8 || sigma_q8 || v_q8)
//! ```
//!
//! `payload_base = ((10 + meta_len + 3) & !3) + 1`. Each sketch's
//! `offset` in the metadata is relative to `payload_base`.
//!
//! ## Metadata JSON shape
//!
//! ```jsonc
//! {
//!   "name": "qwen-coder-7b",
//!   "codec": "fp32",
//!   "topology": "rank-k-exclusion-sketch",
//!   "config": { "arch", "hidden_dim", "num_layers", "vocab_size", … },
//!   "sketches": {
//!     "blk.0.attn_q.weight": {
//!       "offset": 0, "length": 131104, "type": "SK32",
//!       "d_out": 3584, "d_in": 3584, "rank": 32,
//!       "u_max": …, "sigma_max": …, "v_max": …,
//!       "u_q8_len": 114688, "sigma_q8_len": 32, "v_q8_len": 114688
//!     }, …
//!   }
//! }
//! ```
//!
//! ## Per-sketch payload + dequantization
//!
//! ```text
//! bytes [0, u_q8_len)                          : u_q8     (uint8, d_out × rank, row-major)
//! bytes [u_q8_len, u_q8_len+sigma_q8_len)      : sigma_q8 (uint8, rank)
//! bytes [..]                                   : v_q8     (uint8, rank × d_in, row-major)
//! ```
//!
//! `u`/`v` are offset-128 signed-uint8: `x = ((q-128)/127)*max`.
//! `sigma` is unsigned: `x = (q/255)*sigma_max`. Reconstruction:
//! `W[d_out, d_in] = U · diag(σ) · Vᵀ`, served row-major fp32 LE — the
//! exact `[out_dim, in_dim]` byte layout `model.rs::mat_vec_dispatch_batch`
//! expects (M = out_dim, K = in_dim), so NO transpose is applied. This
//! mirrors `sketch_knot_format.py:reconstruct_sketch`.

use std::collections::HashMap;
use std::fs::File;
use std::io::{Read, Seek, SeekFrom};
use std::path::{Path, PathBuf};
use std::sync::{Arc, Mutex};

use crate::loader::{OwnedBytes, TensorInfo, WeightBackend};

/// First two bytes of the dense / sketch "KNOT" magic. `RknotBackend`
/// uses this to sniff whether a `--rknot` source is actually a KNOT-format
/// sketch file before it commits to the `.rknot` reader.
pub const KNOT_MAGIC: &[u8; 4] = b"KNOT";

/// Parsed SK32 sketch entry metadata (the JSON object per tensor).
#[derive(Debug, Clone)]
struct SketchMeta {
    offset: u64,
    d_out: usize,
    d_in: usize,
    rank: usize,
    u_max: f32,
    sigma_max: f32,
    v_max: f32,
    u_q8_len: usize,
    sigma_q8_len: usize,
    v_q8_len: usize,
}

/// `WeightBackend` over a KNOT-format SK32 sketch file. Holds only the
/// parsed metadata + payload base offset; each tensor is reconstructed
/// from disk on demand in `fetch_tensor` (no eager dense expansion).
pub struct SketchBackend {
    path: PathBuf,
    payload_base: u64,
    /// `tensor_name → SketchMeta`. Each tensor is registered under every
    /// name the pipeline might fetch it by (GGUF dot, bitwise underscore,
    /// and the `attn_o`↔`attn_output` divergence), so the map holds
    /// several keys per distinct sketch.
    sketches: HashMap<String, SketchMeta>,
    /// Count of distinct SK32 sketches (file entries actually served),
    /// independent of how many alias keys each one has.
    distinct_count: usize,
    /// Optional dense fallback for any tensor not carried as a sketch
    /// (norms, biases, embeddings, lm_head). Same role as
    /// `RknotBackend::dense_fallback`.
    dense_fallback: Option<Arc<dyn WeightBackend>>,
    /// Lazily reconstructed sketch tensors. Weight bytes are immutable, and
    /// repeat decode tokens fetch the same matrices every step.
    decoded_cache: Mutex<HashMap<String, Arc<Vec<u8>>>>,
}

/// All names the pipeline might fetch a sketch tensor by, given its GGUF
/// dot-style key from the file. Covers: the bitwise underscore form, and
/// the `attn_o` → `attn_output` rename (the sketch generator and the
/// dense `.knot` / `model.rs` disagree on the output-projection name).
fn sketch_name_aliases(dot_name: &str) -> Vec<String> {
    let mut out = Vec::new();
    let underscore = dot_name.replace('.', "_");
    if underscore != dot_name {
        out.push(underscore.clone());
    }
    // attn_o (sketch) <-> attn_output (dense knot / model.rs).
    if dot_name.contains(".attn_o.") {
        let output_dot = dot_name.replace(".attn_o.", ".attn_output.");
        out.push(output_dot.clone());
        out.push(output_dot.replace('.', "_"));
    }
    out
}

#[derive(Debug)]
pub enum SketchError {
    Io(std::io::Error),
    BadMagic { found: [u8; 4] },
    Json(String),
    Format(String),
}

impl std::fmt::Display for SketchError {
    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
        match self {
            SketchError::Io(e) => write!(f, "sketch io: {}", e),
            SketchError::BadMagic { found } => {
                write!(
                    f,
                    "sketch bad magic: {:?} (expected {:?})",
                    found, KNOT_MAGIC
                )
            }
            SketchError::Json(e) => write!(f, "sketch json: {}", e),
            SketchError::Format(e) => write!(f, "sketch format: {}", e),
        }
    }
}

impl std::error::Error for SketchError {}

impl From<std::io::Error> for SketchError {
    fn from(e: std::io::Error) -> Self {
        SketchError::Io(e)
    }
}

/// Cheap content sniff: does `path` begin with the four-byte "KNOT"
/// magic? Used by `RknotBackend::open` to route to the sketch reader.
pub fn is_knot_magic(path: &Path) -> bool {
    let mut f = match File::open(path) {
        Ok(f) => f,
        Err(_) => return false,
    };
    let mut magic = [0u8; 4];
    f.read_exact(&mut magic).is_ok() && &magic == KNOT_MAGIC
}

impl SketchBackend {
    /// Open a KNOT-format SK32 sketch file. Parses the JSON metadata and
    /// records the payload base offset; defers all dequant to fetch time.
    pub fn open(path: &Path) -> Result<Self, SketchError> {
        let mut f = File::open(path)?;

        let mut magic = [0u8; 4];
        f.read_exact(&mut magic)?;
        if &magic != KNOT_MAGIC {
            return Err(SketchError::BadMagic { found: magic });
        }
        let mut ver = [0u8; 2];
        f.read_exact(&mut ver)?;
        let _version = u16::from_le_bytes(ver);
        let mut mlen = [0u8; 4];
        f.read_exact(&mut mlen)?;
        let meta_len = u32::from_le_bytes(mlen) as usize;

        let mut meta_bytes = vec![0u8; meta_len];
        f.read_exact(&mut meta_bytes)?;
        let meta: serde_json::Value =
            serde_json::from_slice(&meta_bytes).map_err(|e| SketchError::Json(e.to_string()))?;

        // Confirm this is a sketch knot, not (somehow) a dense KNOT.
        let topology = meta.get("topology").and_then(|v| v.as_str()).unwrap_or("");
        if !topology.contains("sketch") {
            return Err(SketchError::Format(format!(
                "KNOT file has topology={:?}, not a rank-k-exclusion-sketch; \
                 this is a dense .knot, use --dense / --knot for it",
                topology
            )));
        }

        // payload_base = ((10 + meta_len + 3) & !3) + 1  (pad to 4-byte
        // boundary, then one codec-marker byte). Mirrors the writer.
        let cur = 10 + meta_len;
        let payload_pre_marker = (cur + 3) & !3;
        let payload_base = (payload_pre_marker + 1) as u64;

        let sketches_obj = meta
            .get("sketches")
            .and_then(|v| v.as_object())
            .ok_or_else(|| SketchError::Format("metadata missing `sketches` object".to_string()))?;

        let mut sketches = HashMap::with_capacity(sketches_obj.len() * 2);
        let mut distinct_count = 0usize;
        for (name, entry) in sketches_obj {
            let g_u64 = |k: &str| -> Result<u64, SketchError> {
                entry.get(k).and_then(|v| v.as_u64()).ok_or_else(|| {
                    SketchError::Format(format!("sketch {} missing u64 `{}`", name, k))
                })
            };
            let g_f32 = |k: &str| -> Result<f32, SketchError> {
                entry
                    .get(k)
                    .and_then(|v| v.as_f64())
                    .map(|v| v as f32)
                    .ok_or_else(|| {
                        SketchError::Format(format!("sketch {} missing f32 `{}`", name, k))
                    })
            };
            let ty = entry.get("type").and_then(|v| v.as_str()).unwrap_or("");
            if ty != "SK32" {
                // Skip unknown sketch types rather than fail the whole file.
                continue;
            }
            // The embedding table (`token_embd.weight`) and output projection
            // (`output.weight`) are NOT low-rank — a rank-32 sketch of a
            // 152064×3584 vocab table is a catastrophic approximation that
            // poisons /embed with NaN-grade error. Mirror RknotBackend's
            // spectral-subspace-only policy: leave embeddings / lm_head to
            // the dense fallback. Only the per-layer attention + FFN weight
            // matrices (which the encoder actually targets) are served from
            // sketches.
            if name == "token_embd.weight" || name == "output.weight" {
                continue;
            }
            let m = SketchMeta {
                offset: g_u64("offset")?,
                d_out: g_u64("d_out")? as usize,
                d_in: g_u64("d_in")? as usize,
                rank: g_u64("rank")? as usize,
                u_max: g_f32("u_max")?,
                sigma_max: g_f32("sigma_max")?,
                v_max: g_f32("v_max")?,
                u_q8_len: g_u64("u_q8_len")? as usize,
                sigma_q8_len: g_u64("sigma_q8_len")? as usize,
                v_q8_len: g_u64("v_q8_len")? as usize,
            };
            // Shape consistency: U is [d_out, rank], Vᵀ is [rank, d_in].
            if m.u_q8_len != m.d_out * m.rank
                || m.v_q8_len != m.rank * m.d_in
                || m.sigma_q8_len != m.rank
            {
                return Err(SketchError::Format(format!(
                    "sketch {} dim mismatch: u_q8_len={} (d_out*rank={}), \
                     v_q8_len={} (rank*d_in={}), sigma_q8_len={} (rank={})",
                    name,
                    m.u_q8_len,
                    m.d_out * m.rank,
                    m.v_q8_len,
                    m.rank * m.d_in,
                    m.sigma_q8_len,
                    m.rank
                )));
            }
            // Register every name the pipeline might fetch this tensor by.
            // The dense `.knot` metadata stores tensor names in bitwise
            // underscore form (`blk_0_attn_q_weight`, after `.bin` strip), so
            // `model.rs::resolve_tensor` fetches by the underscore name — not
            // the GGUF dot name the sketch file uses as its key. Without the
            // alias the fetch falls through to the dense fallback and the
            // matmul gets raw Q4_K bytes (reinterpreted as fp32) instead of
            // the sketch reconstruction. Mirrors `RknotBackend::tensor_names`.
            //
            // One naming divergence: the sketch generator names the output
            // projection `attn_o`, but the dense knot / model.rs call it
            // `attn_output`. Map both so the o-projection is served from the
            // sketch too (else it silently uses dense Q4_K bytes).
            for alias in sketch_name_aliases(name) {
                sketches.insert(alias, m.clone());
            }
            sketches.insert(name.clone(), m);
            distinct_count += 1;
        }

        Ok(SketchBackend {
            path: path.to_path_buf(),
            payload_base,
            sketches,
            distinct_count,
            dense_fallback: None,
            decoded_cache: Mutex::new(HashMap::new()),
        })
    }

    /// Attach a dense `.knot` `WeightBackend` for non-sketch tensors
    /// (norms / biases / anything not factored). Same contract as
    /// `RknotBackend::with_dense_fallback`.
    pub fn with_dense_fallback(mut self, fallback: Arc<dyn WeightBackend>) -> Self {
        self.dense_fallback = Some(fallback);
        self
    }

    /// Number of distinct SK32 sketches actually served (file entries,
    /// minus the embedding / output tables left to the dense fallback),
    /// independent of how many alias keys each one carries.
    pub fn sketch_count(&self) -> usize {
        self.distinct_count
    }

    /// Iterate the tensor names served directly from sketches (both naming
    /// conventions).
    pub fn sketch_names(&self) -> impl Iterator<Item = &String> {
        self.sketches.keys()
    }

    /// fp32 `TensorInfo` overrides for every sketch tensor. The paired
    /// dense `.knot` metadata marks these tensors Q4_K / Q6_K, but the
    /// SketchBackend serves reconstructed fp32. Without an override the
    /// matmul kernel parses fp32 bytes as Q4_K super-blocks → instant
    /// NaN. The caller merges these into the metadata before
    /// `KnotWeights::from_parts` (mirrors `RknotBackend::fp32_tensor_overrides`
    /// + `KnotWeights::from_rknot`). Emits both the GGUF dot name (as
    /// stored) and the bitwise underscore variant so qtype resolution
    /// hits regardless of which the pipeline asks for.
    pub fn fp32_tensor_overrides(&self) -> Vec<(String, TensorInfo)> {
        let mut out = Vec::with_capacity(self.sketches.len());
        // self.sketches already holds both name forms (dot + underscore),
        // so iterating covers every key the pipeline might resolve to.
        for (name, meta) in &self.sketches {
            out.push((
                name.clone(),
                TensorInfo {
                    offset: 0,
                    length: (meta.d_out as u64) * (meta.d_in as u64) * 4,
                    tensor_type: "fp32".to_string(),
                    shape: None,
                },
            ));
        }
        out
    }

    /// Reconstruct one tensor `W[d_out, d_in] = U·diag(σ)·Vᵀ` and return
    /// it row-major fp32 little-endian.
    fn reconstruct(&self, meta: &SketchMeta) -> Result<Vec<u8>, String> {
        let mut f = File::open(&self.path).map_err(|e| e.to_string())?;
        let abs = self.payload_base + meta.offset;
        f.seek(SeekFrom::Start(abs)).map_err(|e| e.to_string())?;
        let total = meta.u_q8_len + meta.sigma_q8_len + meta.v_q8_len;
        let mut payload = vec![0u8; total];
        f.read_exact(&mut payload).map_err(|e| e.to_string())?;

        let (u_bytes, rest) = payload.split_at(meta.u_q8_len);
        let (sigma_bytes, v_bytes) = rest.split_at(meta.sigma_q8_len);

        // Dequantize σ into a flat rank-length vector.
        let mut sigma = vec![0f32; meta.rank];
        for r in 0..meta.rank {
            sigma[r] = (sigma_bytes[r] as f32 / 255.0) * meta.sigma_max;
        }

        // Pre-fold σ into V so the reconstruction is a single U·(σV) GEMM.
        // sigma_v[r, j] = sigma[r] * ((v_q8[r,j] - 128)/127) * v_max
        // V is [rank, d_in] row-major.
        let d_in = meta.d_in;
        let d_out = meta.d_out;
        let rank = meta.rank;
        let mut sigma_v = vec![0f32; rank * d_in];
        let v_scale = meta.v_max / 127.0;
        for r in 0..rank {
            let s = sigma[r];
            let row = r * d_in;
            for j in 0..d_in {
                let q = v_bytes[row + j] as i32 - 128;
                sigma_v[row + j] = s * (q as f32) * v_scale;
            }
        }

        // W[i, j] = sum_r U[i, r] * sigma_v[r, j]. U is [d_out, rank].
        // Accumulate in a flat f32 buffer (one row at a time, rank-deep),
        // then serialize to LE bytes once at the end. Doing the f32<->bytes
        // round-trip per element inside the inner loop is ~50× slower and
        // turns a 7-tensor-per-layer forward into minutes.
        let u_scale = meta.u_max / 127.0;
        let mut w = vec![0f32; d_out * d_in];
        for i in 0..d_out {
            let u_row = i * rank;
            let out_row = i * d_in;
            let row = &mut w[out_row..out_row + d_in];
            for r in 0..rank {
                let uq = u_bytes[u_row + r] as i32 - 128;
                let u = (uq as f32) * u_scale;
                if u == 0.0 {
                    continue;
                }
                let sv_row = r * d_in;
                let sv = &sigma_v[sv_row..sv_row + d_in];
                for j in 0..d_in {
                    row[j] += u * sv[j];
                }
            }
        }

        // Serialize to little-endian fp32 bytes (the layout model.rs reads
        // f32 weights as).
        let mut out = vec![0u8; d_out * d_in * 4];
        for (k, &v) in w.iter().enumerate() {
            out[k * 4..k * 4 + 4].copy_from_slice(&v.to_le_bytes());
        }
        Ok(out)
    }
}

impl WeightBackend for SketchBackend {
    fn fetch_tensor(&self, name: &str) -> Result<OwnedBytes, String> {
        if let Some(meta) = self.sketches.get(name) {
            {
                let cache = self
                    .decoded_cache
                    .lock()
                    .map_err(|_| "sketch backend: decoded cache mutex poisoned".to_string())?;
                if let Some(bytes) = cache.get(name) {
                    return Ok(OwnedBytes::Owned(Arc::clone(bytes)));
                }
            }
            let decoded = Arc::new(self.reconstruct(meta)?);
            let mut cache = self
                .decoded_cache
                .lock()
                .map_err(|_| "sketch backend: decoded cache mutex poisoned".to_string())?;
            let bytes = Arc::clone(cache.entry(name.to_string()).or_insert(decoded));
            return Ok(OwnedBytes::Owned(bytes));
        }
        if let Some(fallback) = &self.dense_fallback {
            return fallback.fetch_tensor(name);
        }
        Err(format!(
            "sketch backend: tensor `{}` not in SK32 sketch set and no \
             dense fallback attached",
            name
        ))
    }

    fn has_tensor(&self, name: &str) -> bool {
        if self.sketches.contains_key(name) {
            return true;
        }
        if let Some(fallback) = &self.dense_fallback {
            return fallback.has_tensor(name);
        }
        false
    }

    fn as_any(&self) -> &dyn std::any::Any {
        self
    }
}

#[cfg(test)]
mod tests {
    use super::*;
    use std::io::Write;

    /// Hand-build a minimal KNOT-format SK32 file with one tiny sketch and
    /// confirm the reader + reconstruction round-trips against an explicit
    /// U·diag(σ)·Vᵀ computed in plain f64.
    fn write_one_sketch_knot(path: &Path) -> (usize, usize, usize, Vec<f32>) {
        let d_out = 2usize;
        let d_in = 3usize;
        let rank = 2usize;

        // Quantized factors (offset-128 signed for U/V, unsigned for σ).
        let u_q8: Vec<u8> = vec![200, 100, 90, 160]; // [d_out, rank]
        let sigma_q8: Vec<u8> = vec![255, 128]; // [rank]
        let v_q8: Vec<u8> = vec![150, 110, 130, 120, 200, 90]; // [rank, d_in]
        let u_max = 0.5f32;
        let sigma_max = 4.0f32;
        let v_max = 0.25f32;

        // Reference reconstruction (mirrors reconstruct_sketch).
        let u: Vec<f32> = u_q8
            .iter()
            .map(|&q| ((q as f32) - 128.0) / 127.0 * u_max)
            .collect();
        let sigma: Vec<f32> = sigma_q8
            .iter()
            .map(|&q| (q as f32) / 255.0 * sigma_max)
            .collect();
        let v: Vec<f32> = v_q8
            .iter()
            .map(|&q| ((q as f32) - 128.0) / 127.0 * v_max)
            .collect();
        let mut expect = vec![0f32; d_out * d_in];
        for i in 0..d_out {
            for j in 0..d_in {
                let mut acc = 0f32;
                for r in 0..rank {
                    acc += u[i * rank + r] * sigma[r] * v[r * d_in + j];
                }
                expect[i * d_in + j] = acc;
            }
        }

        let meta = serde_json::json!({
            "name": "test",
            "codec": "fp32",
            "topology": "rank-k-exclusion-sketch",
            "config": {"arch": "qwen2", "hidden_dim": 2},
            "sketches": {
                "blk.0.attn_q.weight": {
                    "offset": 0,
                    "length": u_q8.len() + sigma_q8.len() + v_q8.len(),
                    "type": "SK32",
                    "d_out": d_out, "d_in": d_in, "rank": rank,
                    "u_max": u_max, "sigma_max": sigma_max, "v_max": v_max,
                    "u_q8_len": u_q8.len(),
                    "sigma_q8_len": sigma_q8.len(),
                    "v_q8_len": v_q8.len(),
                }
            }
        });
        let meta_bytes = serde_json::to_vec(&meta).unwrap();
        let meta_len = meta_bytes.len();
        let cur = 10 + meta_len;
        let pre_marker = (cur + 3) & !3;
        let pad = pre_marker - cur;

        let mut f = File::create(path).unwrap();
        f.write_all(KNOT_MAGIC).unwrap();
        f.write_all(&1u16.to_le_bytes()).unwrap();
        f.write_all(&(meta_len as u32).to_le_bytes()).unwrap();
        f.write_all(&meta_bytes).unwrap();
        f.write_all(&vec![0u8; pad]).unwrap();
        f.write_all(&[1u8]).unwrap(); // codec marker
        f.write_all(&u_q8).unwrap();
        f.write_all(&sigma_q8).unwrap();
        f.write_all(&v_q8).unwrap();

        (d_out, d_in, rank, expect)
    }

    #[test]
    fn open_and_reconstruct_round_trips() {
        let p = std::env::temp_dir().join(format!("sketch-bk-{}.knot", std::process::id()));
        let (d_out, d_in, _rank, expect) = write_one_sketch_knot(&p);

        assert!(is_knot_magic(&p));
        let backend = SketchBackend::open(&p).expect("open");
        assert_eq!(backend.sketch_count(), 1);
        assert!(backend.has_tensor("blk.0.attn_q.weight"));

        let bytes = backend.fetch_tensor("blk.0.attn_q.weight").expect("fetch");
        assert_eq!(bytes.len(), d_out * d_in * 4);
        let got: Vec<f32> = bytes
            .chunks_exact(4)
            .map(|c| f32::from_le_bytes([c[0], c[1], c[2], c[3]]))
            .collect();
        for (g, e) in got.iter().zip(expect.iter()) {
            assert!(
                (g - e).abs() < 1e-5,
                "reconstruction mismatch: got {} expected {}",
                g,
                e
            );
        }
        let _ = std::fs::remove_file(&p);
    }

    #[test]
    fn missing_tensor_without_fallback_errors() {
        let p = std::env::temp_dir().join(format!("sketch-bk-miss-{}.knot", std::process::id()));
        let _ = write_one_sketch_knot(&p);
        let backend = SketchBackend::open(&p).expect("open");
        let err = match backend.fetch_tensor("blk.9.ffn_down.weight") {
            Ok(_) => panic!("expected error for missing tensor without fallback"),
            Err(e) => e,
        };
        assert!(err.contains("dense fallback"), "msg: {}", err);
        assert!(!backend.has_tensor("blk.9.ffn_down.weight"));
        let _ = std::fs::remove_file(&p);
    }
}
